#!/usr/bin/env node
/**
 * Script to find unused assets in the project
 * Scans src/assets and checks if files are referenced in code
 */

const fs = require('fs');
const path = require('path');

const PROJECT_ROOT = path.join(__dirname, '..');
const ASSETS_DIR = path.join(PROJECT_ROOT, 'src/assets');
const SRC_DIR = path.join(PROJECT_ROOT, 'src');

// Asset file extensions to check
const ASSET_EXTENSIONS = ['.png', '.jpg', '.jpeg', '.gif', '.svg', '.json', '.webp'];

// Code file extensions
const CODE_EXTENSIONS = ['.ts', '.tsx', '.js', '.jsx'];

/**
 * Recursively get all files in a directory
 */
function getAllFiles(dirPath, arrayOfFiles = []) {
  if (!fs.existsSync(dirPath)) return arrayOfFiles;

  const files = fs.readdirSync(dirPath);

  files.forEach(file => {
    const fullPath = path.join(dirPath, file);
    if (fs.statSync(fullPath).isDirectory()) {
      getAllFiles(fullPath, arrayOfFiles);
    } else {
      arrayOfFiles.push(fullPath);
    }
  });

  return arrayOfFiles;
}

/**
 * Get all asset files
 */
function getAssetFiles() {
  const allFiles = getAllFiles(ASSETS_DIR);
  return allFiles.filter(file => {
    const ext = path.extname(file).toLowerCase();
    return ASSET_EXTENSIONS.includes(ext);
  });
}

/**
 * Get all code files
 */
function getCodeFiles() {
  const allFiles = getAllFiles(SRC_DIR);
  return allFiles.filter(file => {
    const ext = path.extname(file).toLowerCase();
    return CODE_EXTENSIONS.includes(ext);
  });
}

/**
 * Read all code content
 */
function readAllCodeContent(codeFiles) {
  return codeFiles.map(file => {
    try {
      return fs.readFileSync(file, 'utf-8');
    } catch (e) {
      return '';
    }
  }).join('\n');
}

/**
 * Check if an asset is referenced in code
 */
function isAssetUsed(assetPath, codeContent) {
  const basename = path.basename(assetPath);
  const basenameNoExt = path.basename(assetPath, path.extname(assetPath));

  // Various ways assets might be referenced
  const patterns = [
    basename,                          // exact filename
    basenameNoExt,                     // filename without extension
    `'${basename}'`,                   // in quotes
    `"${basename}"`,                   // in double quotes
    `\`${basename}\``,                 // in template literals
    `/${basenameNoExt}`,               // as path segment
  ];

  return patterns.some(pattern => codeContent.includes(pattern));
}

/**
 * Main function
 */
function main() {
  console.log('\n' + '='.repeat(60));
  console.log('  UNUSED ASSETS DETECTION');
  console.log('='.repeat(60) + '\n');

  // Get all assets and code files
  const assetFiles = getAssetFiles();
  const codeFiles = getCodeFiles();

  console.log(`📁 Found ${assetFiles.length} asset files`);
  console.log(`📄 Found ${codeFiles.length} code files`);
  console.log('');

  // Read all code content
  const codeContent = readAllCodeContent(codeFiles);

  // Find unused assets
  const unusedAssets = assetFiles.filter(asset => !isAssetUsed(asset, codeContent));

  // Group by directory
  const groupedAssets = {};
  unusedAssets.forEach(asset => {
    const relativePath = path.relative(ASSETS_DIR, asset);
    const dir = path.dirname(relativePath);
    if (!groupedAssets[dir]) {
      groupedAssets[dir] = [];
    }
    groupedAssets[dir].push(path.basename(asset));
  });

  // Display results
  if (unusedAssets.length === 0) {
    console.log('✅ All assets appear to be used!');
  } else {
    console.log('⚠️  POTENTIALLY UNUSED ASSETS:\n');

    Object.keys(groupedAssets).sort().forEach(dir => {
      console.log(`📂 ${dir || '(root)'}/`);
      groupedAssets[dir].forEach(file => {
        console.log(`   - ${file}`);
      });
      console.log('');
    });

    console.log('-'.repeat(60));
    console.log(`\n📊 SUMMARY: ${unusedAssets.length} potentially unused assets\n`);

    // Calculate potential space savings
    let totalSize = 0;
    unusedAssets.forEach(asset => {
      try {
        totalSize += fs.statSync(asset).size;
      } catch (e) {}
    });
    const sizeKB = (totalSize / 1024).toFixed(2);
    const sizeMB = (totalSize / 1024 / 1024).toFixed(2);
    console.log(`💾 Potential space savings: ${sizeKB} KB (${sizeMB} MB)\n`);

    // Output full paths for easy deletion
    console.log('📋 FULL PATHS (for deletion):\n');
    unusedAssets.forEach(asset => {
      console.log(path.relative(PROJECT_ROOT, asset));
    });
  }

  console.log('\n' + '='.repeat(60));
  console.log('  NOTE: Review carefully before deleting!');
  console.log('  Some assets may be loaded dynamically.');
  console.log('='.repeat(60) + '\n');
}

main();

